function getISOWeek(d) {
  const t = new Date(d.getTime()); t.setHours(0, 0, 0, 0);
  t.setDate(t.getDate() + 3 - ((t.getDay() + 6) % 7));
  const w1 = new Date(t.getFullYear(), 0, 4);
  return { year: t.getFullYear(), week: 1 + Math.round(((t - w1) / 864e5 - 3 + ((w1.getDay() + 6) % 7)) / 7) };
}

// ═══════════════════════════════════════════════════════════════
// IMF DOTS — LIVE API FETCH
// Fetches real Direction of Trade Statistics from the IMF API.
// Uses mirror statistics: World (W00) as reporter, Iran (IR) as counterpart.
// Falls back to synthetic data if the API is unreachable.
// ═══════════════════════════════════════════════════════════════
const IMF_API_BASE = "https://dataservices.imf.org/REST/SDMX_JSON.svc";

async function fetchIMFDOTS() {
  // Start from ~5 years ago (independent of WEEKS to avoid circular dependency)
  const startYear = new Date(new Date().getTime() - 260 * 7 * 864e5).getFullYear();
  const url = `${IMF_API_BASE}/CompactData/DOT/M.W00.TXG_FOB_USD+TMG_CIF_USD.IR?startPeriod=${startYear}`;

  const response = await fetch(url);
  if (!response.ok) throw new Error(`IMF API returned ${response.status}`);

  const data = await response.json();
  const series = data?.CompactData?.DataSet?.Series;
  if (!series) throw new Error("Unexpected IMF API response structure");

  // Series can be a single object or an array; normalise to array
  const seriesArr = Array.isArray(series) ? series : [series];

  // Extract observations keyed by indicator
  const byIndicator = {};
  for (const s of seriesArr) {
    const indicator = s["@INDICATOR"];
    const obs = Array.isArray(s.Obs) ? s.Obs : s.Obs ? [s.Obs] : [];
    byIndicator[indicator] = {};
    for (const o of obs) {
      const period = o["@TIME_PERIOD"]; // "2020-01"
      const value = parseFloat(o["@OBS_VALUE"]);
      if (period && !isNaN(value)) {
        byIndicator[indicator][period] = Math.round(value); // already in millions USD
      }
    }
  }

  const txgData = byIndicator["TXG_FOB_USD"] || {};
  const tmgData = byIndicator["TMG_CIF_USD"] || {};

  // Merge all months present in either series
  const allMonths = new Set([...Object.keys(txgData), ...Object.keys(tmgData)]);
  const months = [...allMonths].sort().map(date => {
    const txg = txgData[date] || 0;
    const tmg = tmgData[date] || 0;
    const d = new Date(date + "-01");
    return {
      date,
      lbl: d.toLocaleDateString("en-GB", { month: "short", year: "2-digit" }),
      txg, tmg, total: txg + tmg,
    };
  });

  if (months.length === 0) throw new Error("No data returned from IMF API");
  return months;
}

