// IMF PortWatch — LIVE AIS PORT DATA (FREE, NO AUTH)
// Daily port calls + import/export volumes by vessel type for
// all global ports, 2019–present. Filtered here for Iran (IRN).
// ═══════════════════════════════════════════════════════════════
const PORTWATCH_BASE = "https://services9.arcgis.com/weJ1QsnbMYJlCHdG/arcgis/rest/services/Daily_Ports_Data/FeatureServer/0/query";

const PORTWATCH_FIELDS = [
  "date", "portid", "portname", "ISO3",
  "portcalls_container", "portcalls_dry_bulk", "portcalls_general_cargo",
  "portcalls_roro", "portcalls_tanker", "portcalls",
  "import_container", "import_dry_bulk", "import_general_cargo",
  "import_roro", "import_tanker",
  "export_container", "export_dry_bulk", "export_general_cargo",
  "export_roro", "export_tanker",
].join(",");

// Map PortWatch field names → dashboard vessel categories
const PW_CAT_MAP = {
  container:     { calls: "portcalls_container",     imp: "import_container",     exp: "export_container" },
  bulk_dry:      { calls: "portcalls_dry_bulk",      imp: "import_dry_bulk",      exp: "export_dry_bulk" },
  tanker:        { calls: "portcalls_tanker",        imp: "import_tanker",        exp: "export_tanker" },
  general_cargo: { calls: "portcalls_general_cargo", imp: "import_general_cargo", exp: "export_general_cargo" },
  gas_carrier:   { calls: "portcalls_roro",          imp: "import_roro",          exp: "export_roro" },
};

// Map PortWatch port names → dashboard port IDs and regions
const PW_PORT_LOOKUP = {
  "Bandar Abbas":           { id: 1, region: "southern" },
  "Bandar Imam Khomeini":   { id: 2, region: "southern" },
  "Assaluyeh":              { id: 3, region: "southern" },
  "Kharg Island":           { id: 4, region: "southern" },
  "Chabahar":               { id: 5, region: "southern" },
  "Bandar-e Anzali":        { id: 6, region: "northern" },
  "Anzali":                 { id: 6, region: "northern" },
  "Bushehr":                { id: 7, region: "southern" },
  "Amirabad":               { id: 8, region: "northern" },
  "Bandar Lengeh":          { id: 9, region: "southern" },
  "Nowshahr":               { id: 10, region: "northern" },
  "Noshahr":                { id: 10, region: "northern" },
};

async function fetchPortWatchData() {
  const now = new Date();
  const startDate = new Date(now.getTime() - 260 * 7 * 864e5); // ~5 years
  const startEpoch = startDate.getTime();
  const where = `ISO3='IRN' AND date>=${startEpoch}`;

  // Paginate through all results
  const allFeatures = [];
  let offset = 0;
  const pageSize = 2000;

  while (true) {
    const params = new URLSearchParams({
      where,
      outFields: PORTWATCH_FIELDS,
      orderByFields: "date ASC",
      resultOffset: String(offset),
      resultRecordCount: String(pageSize),
      f: "json",
    });

    const response = await fetch(`${PORTWATCH_BASE}?${params}`);
    if (!response.ok) throw new Error(`PortWatch API returned ${response.status}`);

    const data = await response.json();
    if (data.error) throw new Error(data.error.message || "PortWatch query error");
    if (!data.features || data.features.length === 0) break;

    allFeatures.push(...data.features);
    if (data.features.length < pageSize && !data.exceededTransferLimit) break;
    offset += pageSize;
  }

  if (allFeatures.length === 0) throw new Error("No PortWatch data for Iran (IRN)");

  // Group daily data into ISO-week buckets
  const weekBuckets = {};

  for (const feature of allFeatures) {
    const attr = feature.attributes;
    // ArcGIS returns dates as epoch ms or "YYYY-MM-DD" string — handle both
    const rawDate = attr.date;
    const dateObj = typeof rawDate === "number" ? new Date(rawDate) : new Date(rawDate + "T00:00:00Z");
    if (isNaN(dateObj.getTime())) continue; // skip bad dates

    // Find Monday of ISO week
    const mon = new Date(dateObj);
    mon.setUTCDate(dateObj.getUTCDate() - ((dateObj.getUTCDay() + 6) % 7));
    const weekKey = mon.toISOString().slice(0, 10);

    if (!weekBuckets[weekKey]) {
      const iw = getISOWeek(mon);
      const bucket = {
        date: weekKey, dateObj: mon,
        year: iw.year, isoWeek: iw.week,
        lbl: mon.toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "2-digit" }),
        lblShort: mon.toLocaleDateString("en-GB", { day: "2-digit", month: "short" }),
        ports: {},
        totalCalls: 0, totalDwt: 0, avgCapacity: 0,
      };
      CK.forEach(k => { bucket[k] = 0; bucket[`${k}_dwt`] = 0; });
      weekBuckets[weekKey] = bucket;
    }

    const week = weekBuckets[weekKey];
    const portName = attr.portname;
    const portInfo = PW_PORT_LOOKUP[portName];
    const portId = portInfo ? portInfo.id : portName;

    if (!week.ports[portId]) {
      const pm = { calls: {}, dwt: {}, totalCalls: 0, totalDwt: 0 };
      CK.forEach(k => { pm.calls[k] = 0; pm.dwt[k] = 0; });
      week.ports[portId] = pm;
    }

    const port = week.ports[portId];

    for (const cat of CK) {
      const map = PW_CAT_MAP[cat];
      const calls = attr[map.calls] || 0;
      const volume = (attr[map.imp] || 0) + (attr[map.exp] || 0); // metric tons as DWT proxy

      port.calls[cat] += calls;
      port.dwt[cat] += Math.round(volume);
      port.totalCalls += calls;
      port.totalDwt += Math.round(volume);

      week[cat] += calls;
      week[`${cat}_dwt`] += Math.round(volume);
      week.totalCalls += calls;
      week.totalDwt += Math.round(volume);
    }
  }

  const weeks = Object.values(weekBuckets).sort((a, b) => a.date.localeCompare(b.date));
  for (const w of weeks) {
    w.avgCapacity = w.totalCalls > 0 ? Math.round(w.totalDwt / w.totalCalls) : 0;
  }

  if (weeks.length === 0) throw new Error("No weekly data computed from PortWatch");
  console.log(`PortWatch: loaded ${allFeatures.length} daily records → ${weeks.length} weeks for Iran`);
  return weeks;
}

// ═══════════════════════════════════════════════════════════════
// STATS
// ═══════════════════════════════════════════════════════════════
function weeklyToMonthly(weeks) {
  const byM = {};
  for (const w of weeks) {
    const mo = w.date.slice(0, 7);
    if (!byM[mo]) byM[mo] = { date: mo, totalCalls: 0, totalDwt: 0 };
    byM[mo].totalCalls += w.totalCalls; byM[mo].totalDwt += w.totalDwt;
  }
  return Object.values(byM).sort((a, b) => a.date.localeCompare(b.date));
}

function computeIdxMonthly(months, cw) {
  const dw = 1 - cw, BW = 3;
  const bC = months.slice(0, BW).reduce((s, m) => s + m.totalCalls, 0) / BW;
  const bD = months.slice(0, BW).reduce((s, m) => s + m.totalDwt, 0) / BW;
  return months.map(m => ({
    date: m.date,
    index: (cw * (m.totalCalls / (bC || 1)) + dw * (m.totalDwt / (bD || 1))) * 100
  }));
}

function pearsonR(x, y) {
  const n = x.length; if (n < 3) return { r: 0, r2: 0 };
  const mx = x.reduce((s, v) => s + v, 0) / n, my = y.reduce((s, v) => s + v, 0) / n;
  let num = 0, dx2 = 0, dy2 = 0;
  for (let i = 0; i < n; i++) { const dx = x[i] - mx, dy = y[i] - my; num += dx * dy; dx2 += dx * dx; dy2 += dy * dy; }
  const den = Math.sqrt(dx2 * dy2);
  return { r: den > 0 ? num / den : 0, r2: den > 0 ? (num / den) ** 2 : 0 };
}

function linReg(x, y) {
  const n = x.length, mx = x.reduce((s, v) => s + v, 0) / n, my = y.reduce((s, v) => s + v, 0) / n;
  let num = 0, den = 0;
  for (let i = 0; i < n; i++) { num += (x[i] - mx) * (y[i] - my); den += (x[i] - mx) ** 2; }
  const slope = den > 0 ? num / den : 0;
  return { slope, intercept: my - slope * mx };
}

function calibrate(weeks, dots, metric) {
  const monthly = weeklyToMonthly(weeks), results = [];
  for (let cw = 0; cw <= 100; cw += 5) {
    const idx = computeIdxMonthly(monthly, cw / 100);
    const xV = [], yV = [];
    for (const im of idx) {
      const dm = dots.find(d => d.date === im.date);
      if (dm) { xV.push(im.index); yV.push(metric === "total" ? dm.total : metric === "txg" ? dm.txg : dm.tmg); }
    }
    const { r, r2 } = pearsonR(xV, yV);
    results.push({ callsW: cw, dwtW: 100 - cw, r, r2 });
  }
  return results.sort((a, b) => b.r2 - a.r2);
}

function computeWeeklyIndex(weeks, cw) {
  const dw = 1 - cw, BW = 12;
  const bC = weeks.slice(0, BW).reduce((s, w) => s + w.totalCalls, 0) / BW;
  const bD = weeks.slice(0, BW).reduce((s, w) => s + w.totalDwt, 0) / BW;
  return weeks.map(w => ({
    date: w.date, lbl: w.lblShort, lblFull: w.lbl, year: w.year, isoWeek: w.isoWeek,
    aggregate: Math.round((cw * (w.totalCalls / (bC || 1)) + dw * (w.totalDwt / (bD || 1))) * 100)
  }));
}

// ═══════════════════════════════════════════════════════════════
// PROJECTION ENGINE
// ═══════════════════════════════════════════════════════════════
function projectIndex(indexData, horizonWeeks) {
  const n = indexData.length, vals = indexData.map(d => d.aggregate);
  const fitN = Math.min(52, n);
  const recent = vals.slice(-fitN);
  const { slope, intercept } = linReg(recent.map((_, i) => i), recent);
  const byWeek = {};
  for (const d of indexData) { if (!byWeek[d.isoWeek]) byWeek[d.isoWeek] = []; byWeek[d.isoWeek].push(d.aggregate); }
  const grandMean = vals.reduce((s, v) => s + v, 0) / n;
  const seasonalMean = {};
  for (const [wk, arr] of Object.entries(byWeek)) seasonalMean[wk] = (arr.reduce((s, v) => s + v, 0) / arr.length) - grandMean;
  const residuals = [];
  for (let i = 0; i < fitN; i++) residuals.push(recent[i] - (intercept + slope * i));
  const resStd = Math.sqrt(residuals.reduce((s, r) => s + r * r, 0) / fitN);
  const lastDate = new Date(indexData[n - 1].date);
  const projections = [];
  for (let w = 1; w <= horizonWeeks; w++) {
    const fd = new Date(lastDate.getTime() + w * 7 * 864e5);
    const iw = getISOWeek(fd);
    const central = Math.round(intercept + slope * (fitN - 1 + w) + (seasonalMean[iw.week] || 0));
    const spread = Math.sqrt(w);
    const ci80 = Math.round(1.28 * resStd * spread);
    const ci95 = Math.round(1.96 * resStd * spread);
    projections.push({
      date: fd.toISOString().slice(0, 10),
      lbl: fd.toLocaleDateString("en-GB", { day: "2-digit", month: "short" }),
      lblFull: fd.toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "2-digit" }),
      central, ci80_lo: central - ci80, ci80_hi: central + ci80, ci95_lo: central - ci95, ci95_hi: central + ci95,
    });
  }
  return projections;
}

